mapper.select:
SELECT DISTINCT faib.* FROM FUND_ACCOUNT_INITIAL_BALANCE faib INNER JOIN ( -- 为每个账户找到最近的账期 SELECT t.account_id, MIN(t.period_order) as min_period_order FROM ( SELECT faib_inner.账户编号 as account_id, faib_inner.账期编号 as period_id, ROW_NUMBER() OVER (ORDER BY fp.年份 DESC, fp.月份 DESC) as period_order FROM FUND_ACCOUNT_INITIAL_BALANCE faib_inner INNER JOIN FUND_PERIOD fp ON faib_inner.账期编号 = fp.账期编号 WHERE fp.组织编号 = #{organizationId} AND faib_inner.账户编号 IN
#{accountId}
AND faib_inner.账期编号 IN
#{periodId}
) t GROUP BY t.account_id ) nearest_periods ON faib.账户编号 = nearest_periods.account_id INNER JOIN FUND_PERIOD fp ON faib.账期编号 = fp.账期编号 WHERE fp.组织编号 = #{organizationId} AND ROW_NUMBER() OVER (PARTITION BY faib.账户编号 ORDER BY fp.年份 DESC, fp.月份 DESC) = 1
